  "sentences": [
    {
      "text": "我忘記帶鑰匙，結果進不了家門。",
      "pinyin": "Wǒ wàngjì dài yàoshi, jiéguǒ jìn bù liǎo jiā mén.",
      "pinyin_numeric": "wo3 wang4ji4 dai4 yao4shi5, jie2guo3 jin4 bu4 liao3 jia1 men2.",
      "translation_en": "I forgot to bring my keys, and as a result, I couldn't get into the house.",
      "translation_ko": "열쇠를 가져오는 걸 잊어버려서 결국 집에 들어가지 못했어요."
    },
    {
      "pinyin": "Tā shēngbìng le, jiéguǒ méi qù shàngbān.",
      "pinyin_numeric": "ta1 sheng1bing4 le5, jie2guo3 mei2 qu4 shang4ban1.",
      "text": "他生病了，結果沒去上班。",
      "translation_en": "He got sick, and as a result, he didn't go to work.",
      "translation_ko": "그가 아파서 결국 출근하지 못했어요."
    },
    {
      "pinyin": "Xià yǔ le, jiéguǒ wǒmen méi qù gōngyuán.",
      "pinyin_numeric": "xia4 yu3 le5, jie2guo3 wo3men5 mei2 qu4 gong1yuan2.",
      "text": "下雨了，結果我們沒去公園。",
      "translation_en": "It rained, and as a result, we didn't go to the park.",
      "translation_ko": "비가 와서 결국 우리는 공원에 가지 않았어요."
    },
    {
      "pinyin": "Wǒ bǎ shǒujī nòng diū le, jiéguǒ zhǎo bù dào le.",
      "pinyin_numeric": "wo3 ba3 shou3ji1 nong4 diu1 le5, jie2guo3 zhao3 bu4 dao4 le5.",
      "text": "我把手機弄丟了，結果找不到了。",
      "translation_en": "I lost my phone, and as a result, I couldn't find it.",
      "translation_ko": "핸드폰을 잃어버려서 결국 찾을 수 없게 되었어요."
    },
    {
      "pinyin": "Tā chídào le, jiéguǒ cuòguòle huǒchē.",
      "pinyin_numeric": "ta1 chi2dao4 le5, jie2guo3 cuo4guo4 le5 huo3che1.",
      "text": "他遲到了，結果錯過了火車。",
      "translation_en": "He was late, and as a result, he missed the train.",
      "translation_ko": "그가 지각해서 결국 기차를 놓쳤어요."
    },
    {
      "pinyin": "Sāichē le, jiéguǒ wǒmen wǎn le bàn xiǎoshí.",
      "pinyin_numeric": "sai1che1 le5, jie2guo3 wo3men5 wan3 le5 ban4 xiao3shi2.",
      "text": "塞車了，結果我們晚了半小時。",
      "translation_en": "There was a traffic jam, and as a result, we were half an hour late.",
      "translation_ko": "교통 체증이 나서 결국 우리는 30분 늦었어요."
    },
    {
      "pinyin": "Tā gǎnmào le, jiéguǒ tóu hěn tòng.",
      "pinyin_numeric": "ta1 gan3mao4 le5, jie2guo3 tou2 hen3 tong4.",
      "text": "他感冒了，結果頭很痛。",
      "translation_en": "He caught a cold, and as a result, he had a bad headache.",
      "translation_ko": "그가 감기에 걸려서 결국 머리가 많이 아팠어요."
    },
    {
      "pinyin": "Wǒ wàngjì dài qián, jiéguǒ méi mǎi dōngxi.",
      "pinyin_numeric": "wo3 wang4ji4 dai4 qian2, jie2guo3 mei2 mai3 dong1xi5.",
      "text": "我忘記帶錢，結果沒買東西。",
      "translation_en": "I forgot to bring money, and as a result, I didn't buy anything.",
      "translation_ko": "돈을 가져오는 걸 잊어버려서 결국 아무것도 사지 못했어요."
    },
    {
      "pinyin": "Tā shuāi dǎo le, jiéguǒ shòushāng le.",
      "pinyin_numeric": "ta1 shuai1 dao3 le5, jie2guo3 shou4shang1 le5.",
      "text": "他摔倒了，結果受傷了。",
      "translation_en": "He fell down, and as a result, he got injured.",
      "translation_ko": "그가 넘어져서 결국 다쳤어요."
    },
    {
      "pinyin": "Tāmen chǎojià le, jiéguǒ hěn bù gāoxìng.",
      "pinyin_numeric": "ta1men5 chao3jia4 le5, jie2guo3 hen3 bu4 gao1xing4.",
      "text": "他們吵架了，結果很不高興。",
      "translation_en": "They argued, and as a result, they were very unhappy.",
      "translation_ko": "그들이 싸워서 결국 매우 기분이 나빴어요."
    }
  ]
}
